// Union-Find data structure to manage connected components
typedef struct {
    int parent[c + 1]; // 1-based indexing
    int rank[c + 1];
} UnionFind;

// Function to find the root of a node with path compression
int find(UnionFind *uf, int x) {
    if (uf->parent[x] != x) {
        uf->parent[x] = find(uf, uf->parent[x]); // Path compression
    }
    return uf->parent[x];
}

// Function to union two nodes
void unionSet(UnionFind *uf, int x, int y) {
    int rootX = find(uf, x);
    int rootY = find(uf, y);
    if (rootX != rootY) {
        if (uf->rank[rootX] < uf->rank[rootY]) {
            uf->parent[rootX] = rootY;
        } else {
            uf->parent[rootY] = rootX;
            if (uf->rank[rootX] == uf->rank[rootY]) {
                uf->rank[rootX]++;
            }
        }
    }
}

// Function to solve the problem
Array<Int64> solve(c: Int64, connections: Array<Array<Int64>>, queries: Array<Array<Int64>>) {
    // Initialize Union-Find structure
    UnionFind uf;
    for (int i = 0; i <= c; i++) {
        uf.parent[i] = i;
        uf.rank[i] = 0;
    }

    // Process connections to build the grid
    for (int i = 0; i < connections.length; i++) {
        int u = connections[i][0];
        int v = connections[i][1];
        unionSet(&uf, u, v);
    }

    // Track which nodes are online
    bool online[c + 1];
    for (int i = 0; i <= c; i++) {
        online[i] = true;
    }

    // Process queries
    Array<Int64> result;
    for (int i = 0; i < queries.length; i++) {
        int type = queries[i][0];
        int x = queries[i][1];

        if (type == 1) {
            // Maintenance check query
            if (online[x]) {
                // The node is online, so the answer is x
                result.append(x);
            } else {
                // The node is offline, find the minimum online node in the same grid
                int root = find(&uf, x);
                int minOnline = -1;
                for (int j = 1; j <= c; j++) {
                    if (online[j] && find(&uf, j) == root) {
                        if (minOnline == -1 || j < minOnline) {
                            minOnline = j;
                        }
                    }
                }
                result.append(minOnline);
            }
        } else {
            // Offline query
            online[x] = false;
        }
    }

    return result;
}
